UPDATE employee1
SET
    updateDate = SYSDATE
    , password      = #{password}      
                             , levelCode     = #{levelCode}     
                             , enabled       = #{enabled}       
    , empStatusCode = #{empStatusCode} 
WHERE empId = #{empId}

UPDATE employee2
SET
    name        = #{name}
    , birth       = #{birth}       
                           , profilePhoto= #{profilePhoto}
                           , tel         = #{tel}         
                           , zip         = #{zip}         
                           , addr1       = #{addr1}       
                           , addr2       = #{addr2}       
                           , email       = #{email}       
    , hireDate    = #{hireDate}    
                           , deptCode    = #{deptCode}    
                           , gradeCode   = #{gradeCode}   
WHERE empId = #{empId}

UPDATE employeeAuthority
SET authority = #{authorityCode}
